import { api } from '@semparar/mf-app-user';
import type { RescueApiResponse, RescuePayload } from '../models';

class RescueApi {
  async rescue(payload: RescuePayload): Promise<RescueApiResponse> {
    const response = await api.post<RescueApiResponse>(
      `/fintech/v1/rewardProgram/rescue`,
      payload,
    );
    return response.data;
  }
}

export const rescueApi = new RescueApi();

